// src/pages/AdminDashboard.js
import React from 'react';
import Sidebar from '../components/Sidebar'; // Make sure your sidebar path is correct

const AdminDashboard = () => {
  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar Section */}
      <Sidebar />

      {/* Main Content */}
      <div className="flex-1 p-6">
        <div className="bg-white p-6 rounded-lg shadow-md">
          <h1 className="text-3xl font-bold text-gray-800 mb-4">
            Welcome to Admin Dashboard
          </h1>

          {/* You can customize this section below */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-8">
            <div className="bg-blue-100 p-5 rounded-lg shadow hover:shadow-lg transition">
              <h2 className="text-xl font-semibold text-blue-800">Total Blogs</h2>
              <p className="text-2xl font-bold mt-2">12</p>
            </div>
            <div className="bg-green-100 p-5 rounded-lg shadow hover:shadow-lg transition">
              <h2 className="text-xl font-semibold text-green-800">Total Categories</h2>
              <p className="text-2xl font-bold mt-2">5</p>
            </div>
            <div className="bg-purple-100 p-5 rounded-lg shadow hover:shadow-lg transition">
              <h2 className="text-xl font-semibold text-purple-800">Total Users</h2>
              <p className="text-2xl font-bold mt-2">23</p>
            </div>
          </div>

          {/* You can extend with charts, recent posts, etc. */}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
